Given your stack (Kotlin, gRPC internal, REST external, PostgreSQL), here's the simplest approach:

**REST endpoint** (external-facing, merchant calls it) that internally verifies via micro-deposits or a provider, with state in PostgreSQL.

```kotlin
// payment-service/src/main/kotlin/com/helios/payment/api/BankAccountVerificationController.kt

@RestController
@RequestMapping("/v1/merchants/{merchantId}/bank-accounts")
class BankAccountVerificationController(
    private val verificationService: BankAccountVerificationService
) {
    @PostMapping("/{bankAccountId}/verify")
    suspend fun initiate(
        @PathVariable merchantId: UUID,
        @PathVariable bankAccountId: UUID
    ): ResponseEntity<VerificationResponse> {
        val result = verificationService.initiate(merchantId, bankAccountId)
        return ResponseEntity.status(HttpStatus.ACCEPTED).body(result)
    }

    @PostMapping("/{bankAccountId}/verify/confirm")
    suspend fun confirm(
        @PathVariable merchantId: UUID,
        @PathVariable bankAccountId: UUID,
        @RequestBody request: ConfirmRequest
    ): ResponseEntity<VerificationResponse> {
        val result = verificationService.confirm(merchantId, bankAccountId, request.amounts)
        return ResponseEntity.ok(result)
    }
}

data class ConfirmRequest(val amounts: List<BigDecimal>)

data class VerificationResponse(
    val bankAccountId: UUID,
    val status: VerificationStatus
)

enum class VerificationStatus { PENDING, VERIFIED, FAILED }
```

```kotlin
// payment-service/src/main/kotlin/com/helios/payment/domain/BankAccountVerificationService.kt

@Service
class BankAccountVerificationService(
    private val repo: VerificationRepository,
    private val accountStub: AccountServiceGrpc.AccountServiceCoroutineStub, // gRPC to account-service
    private val eventPublisher: KafkaTemplate<String, VerificationEvent>
) {
    suspend fun initiate(merchantId: UUID, bankAccountId: UUID): VerificationResponse {
        // verify ownership via gRPC to account-service
        val account = accountStub.getBankAccount(
            GetBankAccountRequest.newBuilder()
                .setMerchantId(merchantId.toString())
                .setBankAccountId(bankAccountId.toString())
                .build()
        )

        val verification = repo.save(
            BankAccountVerification(
                bankAccountId = bankAccountId,
                merchantId = merchantId,
                status = VerificationStatus.PENDING,
                attemptsRemaining = 3
            )
        )

        // trigger micro-deposits (async via Kafka → settlement adapter)
        eventPublisher.send("bank-account.verification.initiated",
            VerificationEvent(verification.id, bankAccountId))

        return VerificationResponse(bankAccountId, VerificationStatus.PENDING)
    }

    suspend fun confirm(merchantId: UUID, bankAccountId: UUID, amounts: List<BigDecimal>): VerificationResponse {
        val verification = repo.findByBankAccountIdAndMerchantId(bankAccountId, merchantId)
            ?: throw NotFoundException("No pending verification")

        check(verification.attemptsRemaining > 0) { "Max attempts exceeded" }

        val matched = verification.expectedAmounts.toSet() == amounts.toSet()

        val updated = if (matched) {
            verification.copy(status = VerificationStatus.VERIFIED)
        } else {
            verification.copy(
                status = if (verification.attemptsRemaining <= 1) VerificationStatus.FAILED else VerificationStatus.PENDING,
                attemptsRemaining = verification.attemptsRemaining - 1
            )
        }

        repo.save(updated)
        return VerificationResponse(bankAccountId, updated.status)
    }
}
```

